CREATE TABLE IF NOT EXISTS public.game_sessions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id BIGINT NOT NULL REFERENCES public.users(telegram_id) ON DELETE CASCADE, level_id UUID REFERENCES public.levels(id) ON DELETE SET NULL, map_template_id TEXT, level_index INT, status TEXT NOT NULL DEFAULT 'in_progress' CHECK (status IN ('in_progress','completed','failed','abandoned')), coins_pending INT NOT NULL DEFAULT 0, coins_credited INT NOT NULL DEFAULT 0, revives_used INT NOT NULL DEFAULT 0, paid_revives_used INT NOT NULL DEFAULT 0, started_at TIMESTAMPTZ NOT NULL DEFAULT now(), ended_at TIMESTAMPTZ);
ALTER TABLE public.game_sessions ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.deposits (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id BIGINT NOT NULL REFERENCES public.users(telegram_id) ON DELETE CASCADE, amount_usdt NUMERIC(20,6) NOT NULL, amount_gtc NUMERIC(20,4) NOT NULL, tx_hash TEXT NOT NULL UNIQUE, screenshot_url TEXT, status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','approved','rejected','auto_approved')), verification_data JSONB, admin_note TEXT, reviewed_by BIGINT, reviewed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.deposits ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.transactions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id BIGINT NOT NULL REFERENCES public.users(telegram_id) ON DELETE CASCADE, kind TEXT NOT NULL CHECK (kind IN ('deposit','game_reward','referral_bonus','admin_adjust','revive_spend','level_prize','powerup_spend')), amount_gtc NUMERIC(20,4) NOT NULL, balance_after NUMERIC(20,4) NOT NULL, ref_id UUID, note TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.referrals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), referrer_id BIGINT NOT NULL REFERENCES public.users(telegram_id) ON DELETE CASCADE, referred_id BIGINT NOT NULL REFERENCES public.users(telegram_id) ON DELETE CASCADE, reward_gtc NUMERIC(20,4) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE (referred_id));
ALTER TABLE public.referrals ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.admin_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), admin_id BIGINT NOT NULL, action TEXT NOT NULL, target TEXT, details JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.admin_logs ENABLE ROW LEVEL SECURITY;
DO $$ DECLARE t text; BEGIN FOREACH t IN ARRAY ARRAY['users','admins','announcements','settings','levels','level_objects','game_sessions','deposits','transactions','referrals','admin_logs'] LOOP EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', 'backend_only_deny', t); EXECUTE format('CREATE POLICY %I ON public.%I FOR ALL TO public USING (false) WITH CHECK (false)', 'backend_only_deny', t); END LOOP; END $$;
